CREATE OR REPLACE VIEW v_network_routing SQL SECURITY INVOKER AS 
SELECT node_id, name, location_type, latitude, longitude, capacity 
FROM network_routing;

CREATE OR REPLACE VIEW v_network_routing_segment SQL SECURITY INVOKER AS 
SELECT segment_id, origin_node_id, destination_node_id, distance_km, status 
FROM network_routing_segment;

CREATE OR REPLACE VIEW v_operation SQL SECURITY INVOKER AS 
SELECT operation_id, node_id, operation_type, operating_hours, active 
FROM operation;

CREATE OR REPLACE VIEW v_transit_path SQL SECURITY INVOKER AS 
SELECT path_id, transit_mode, avg_duration_hours 
FROM transit_path;
